(async()=>{const s=document.currentScript.src,p=[];for(let i=0;i<9;i++){const n=String(i).padStart(2,"0");p.push(await(await fetch(new URL("axios-app.part"+n+".txt",s))).text())}const b=atob(p.join("")),u=new Uint8Array(b.length);for(let i=0;i<b.length;i++)u[i]=b.charCodeAt(i);const x=URL.createObjectURL(new Blob([u],{type:"text/javascript"}));try{await import(x)}finally{URL.revokeObjectURL(x)}})();